enum OpenSettingsDestination {
    case location
    case motion
    case notification
    case focus
    case backgroundRefresh

    var url: URL? {
        if Current.isCatalyst {
            let query: String?
            let bundleIdentifier: String?

            switch self {
            case .location:
                bundleIdentifier = "com.apple.preference.security"
                query = "Privacy_LocationServices"
            case .motion:
                bundleIdentifier = nil
                query = nil
            case .notification, .focus:
                bundleIdentifier = "com.apple.preference.notifications"
                query = nil
            case .backgroundRefresh:
                bundleIdentifier = nil
                query = nil
            }

            if let bundleIdentifier {
                return URL(string: "x-apple.systempreferences:\(bundleIdentifier)?\(query ?? "")")!
            } else {
                return nil
            }
        } else {
            return URL(string: UIApplication.openSettingsURLString)!
        }
    }
}

import ClockKit
import Foundation

extension Date {
    func encodedForComplication(family: CLKComplicationFamily) -> Date? {
        let calendar = Calendar.current

        var dc = calendar.dateComponents(in: calendar.timeZone, from: self)
        dc.nanosecond = family.rawValue.millisecondsToNanoseconds

        return calendar.date(from: dc)
    }

    var complicationFamilyFromEncodedDate: CLKComplicationFamily? {
        let calendar = Calendar.current
        let ns = calendar.component(.nanosecond, from: self)

        return CLKComplicationFamily(rawValue: ns.nanosecondsToMilliseconds)
    }
}

extension Int {
    var millisecondsToNanoseconds: Int {
        self * 1_000_000
    }
}

extension Int {
    var nanosecondsToMilliseconds: Int {
        Int(round(Double(self) / 1_000_000))
    }
}

