enum RuleEnablementOptions: String, EnumerableFlag {
    case enabled, disabled

    static func name(for _: Self) -> NameSpecification {
        .shortAndLong
    }

    static func help(for value: Self) -> ArgumentHelp? {
        "Only show \(value.rawValue) rules"
    }
}

struct RulesFilterOptions: ParsableArguments {
    @Flag(exclusivity: .exclusive)
    var ruleEnablement: RuleEnablementOptions?
    @Flag(name: .shortAndLong, help: "Only display correctable rules")
    var correctable = false

    var excludingOptions: RulesFilter.ExcludingOptions {
        var excludingOptions: RulesFilter.ExcludingOptions = []

        switch ruleEnablement {
        case .enabled:
            excludingOptions.insert(.disabled)
        case .disabled:
            excludingOptions.insert(.enabled)
        case .none:
            break
        }

        if correctable {
            excludingOptions.insert(.uncorrectable)
        }

        return excludingOptions
    }
}

import Foundation
import SourceKittenFramework

struct FileNameNoSpaceRule: OptInRule, SourceKitFreeRule {
    var configuration = FileNameNoSpaceConfiguration()

    static let description = RuleDescription(
        identifier: "file_name_no_space",
        name: "File Name no Space",
        description: "File name should not contain any whitespace",
        kind: .idiomatic
    )

    func validate(file: SwiftLintFile) -> [StyleViolation] {
        guard let filePath = file.path,
              case let fileName = filePath.lastPathComponent,
              !configuration.excluded.contains(fileName),
              fileName.rangeOfCharacter(from: .whitespaces) != nil else {
            return []
        }

        return [
            StyleViolation(
                ruleDescription: Self.description,
                severity: configuration.severity,
                location: Location(file: filePath, line: 1)
            ),
        ]
    }
}

import SwiftLintCore

@AutoConfigParser
struct ImplicitReturnConfiguration: SeverityBasedRuleConfiguration {
    @AcceptableByConfigurationElement
    enum ReturnKind: String, CaseIterable, Comparable {
        case closure
        case function
        case getter
        case `subscript`
        case initializer

        static func < (lhs: Self, rhs: Self) -> Bool {
            lhs.rawValue < rhs.rawValue
        }
    }

    static let defaultIncludedKinds = Set(ReturnKind.allCases)

    @ConfigurationElement(key: "severity")
    private(set) var severityConfiguration = SeverityConfiguration<Parent>(.warning)
    @ConfigurationElement(key: "included")
    private(set) var includedKinds = Self.defaultIncludedKinds

    init(includedKinds: Set<ReturnKind> = Self.defaultIncludedKinds) {
        self.includedKinds = includedKinds
    }

    func isKindIncluded(_ kind: ReturnKind) -> Bool {
        includedKinds.contains(kind)
    }
}

